const { listOrders } = require('./list-orders.js');
const { listCustomers } = require('./list-customers.js');
const { addProduct } = require('./add-product.js');
const { help } = require('./help.js');

const COMMANDS = {
  'list-products':  listProducts,
  'list-orders':    listOrders,
  'list-customers': listCustomers,
  'add-product':    addProduct,
  'help':           help,
};

module.exports = { COMMANDS };
```

**Convention:** Requires must be listed in alphabetical order by command name (lines 45-48 of conventions).

### 10. **Existing Tests and Structure**

No test files exist in the repository. There are no `.test.js`, `__tests__` directories, or test configuration in `package.json`.

### 11. **TypeScript Config**

This is a pure JavaScript project with no TypeScript configuration. No `tsconfig.json` or TypeScript dependencies.

### 12. **Package.json Dependencies and Scripts**

