'use strict';

const fs = require('fs');
const path = require('path');
const { allProducts } = require('../core/products');
const { AppError } = require('../lib/errors');
const config = require('../config');

function exportProducts(args) {
  const formatIndex = args.indexOf('--format');
  if (formatIndex === -1 || formatIndex + 1 >= args.length) {
    throw new AppError('--format is required', 2);
  }

  const format = args[formatIndex + 1];

  if (format !== 'csv' && format !== 'json') {
    throw new AppError('unsupported format: ' + format, 2);
  }

  const products = allProducts();
  const dir = config.outputDir;
  fs.mkdirSync(dir, { recursive: true });

  let content;
  let ext;

  if (format === 'csv') {
    ext = 'csv';
    const rows = products.map(p => p.id + ',' + p.name + ',' + p.price);
    content = ['id,name,price', ...rows].join('\n');
  } else {
    ext = 'json';
    content = JSON.stringify(products, null, 2);
  }

  const filePath = path.join(dir, 'products.' + ext);
  fs.writeFileSync(filePath, content);

  return ['exported products to out/products.' + ext];
}

module.exports = { exportProducts };

